package com.weib.entity;
import jakarta.persistence.*; import lombok.Data; import java.time.LocalDateTime;
@Entity @Table(name="forum_sections", indexes=@Index(name="idx_forum_sections_status_sort", columnList="status,sort_order")) @Data
public class ForumSection { @Id @GeneratedValue(strategy=GenerationType.IDENTITY) private Long id; @Column(nullable=false,length=40) private String name; @Column(nullable=false,length=60,unique=true) private String slug; @Column(length=500) private String description; @Column(name="sort_order",nullable=false) private Integer sortOrder=0; @Column(nullable=false,length=20) private String status="ACTIVE"; @Column(name="created_at",nullable=false,updatable=false) private LocalDateTime createdAt; @Column(name="updated_at",nullable=false) private LocalDateTime updatedAt; @PrePersist protected void onCreate(){LocalDateTime n=LocalDateTime.now();createdAt=n;updatedAt=n;} @PreUpdate protected void onUpdate(){updatedAt=LocalDateTime.now();} }
